                            break;
                        case 'ArrowLeft':
                        case 'a':
                        case 'A':
                            if (direction.x !== 1) nextDirection = { x: -1, y: 0 };
                            break;
                        case 'ArrowRight':
                        case 'd':
                        case 'D':
                            if (direction.x !== -1) nextDirection = { x: 1, y: 0 };
                            break;
                        case 'p':
                        case 'P':
                        case 'Escape':
                            togglePause();
                            break;
                    }
                    break;
