                    food.y * CELL_SIZE + CELL_SIZE / 2,
                    CELL_SIZE / 2 - 2,
                    0,
                    Math.PI * 2
                );
                ctx.fill();
                ctx.shadowBlur = 0;
            }

            // 绘制蛇
            if (gameState === 'playing' || gameState === 'paused') {
                snake.forEach((segment, index) => {
                    const x = segment.x * CELL_SIZE;
                    const y = segment.y * CELL_SIZE;

                    // 蛇身渐变
                    const hue = (index * 5) % 360;
                    ctx.fillStyle = index === 0 ? '#4fd1c5' : `hsl(${hue}, 70%, 60%)`;
                    ctx.shadowColor = index === 0 ? '#4fd1c5' : `hsl(${hue}, 70%, 60%)`;
                    ctx.shadowBlur = index === 0 ? 8 : 4;

                    // 绘制圆角矩形
                    const radius = 4;
                    ctx.beginPath();
                    ctx.roundRect(x + 1, y + 1, CELL_SIZE - 2, CELL_SIZE - 2, radius);
                    ctx.fill();
                    ctx.shadowBlur = 0;

                    // 蛇头眼睛
                    if (index === 0) {
                        ctx.fillStyle = 'white';
                        const eyeSize = 3;
                        const eyeOffset = 5;
                        if (direction.x === 1) {
                            ctx.beginPath();
                            ctx.arc(x + CELL_SIZE - eyeOffset, y + eyeOffset, eyeSize, 0, Math.PI * 2);
                            ctx.arc(x + CELL_SIZE - eyeOffset, y + CELL_SIZE - eyeOffset, eyeSize, 0, Math.PI * 2);
                            ctx.fill();
                        } else if (direction.x === -1) {
                            ctx.beginPath();
                            ctx.arc(x + eyeOffset, y + eyeOffset, eyeSize, 0, Math.PI * 2);
                            ctx.arc(x + eyeOffset, y + CELL_SIZE - eyeOffset, eyeSize, 0, Math.PI * 2);
                            ctx.fill();
                        } else if (direction.y === -1) {
                            ctx.beginPath();
                            ctx.arc(x + eyeOffset, y + eyeOffset, eyeSize, 0, Math.PI * 2);
                            ctx.arc(x + CELL_SIZE - eyeOffset, y + eyeOffset, eyeSize, 0, Math.PI * 2);
                            ctx.fill();
                        } else if (direction.y === 1) {
                            ctx.beginPath();
                            ctx.arc(x + eyeOffset, y + CELL_SIZE - eyeOffset, eyeSize, 0, Math.PI * 2);
                            ctx.arc(x + CELL_SIZE - eyeOffset, y + CELL_SIZE - eyeOffset, eyeSize, 0, Math.PI * 2);
                            ctx.fill();
                        }
                    }
                });
            }
        }

        // 开始游戏
        function startGame() {
            // 重置游戏状态
            snake = [
                { x: Math.floor(GRID_COLS / 2), y: Math.floor(GRID_ROWS / 2) }
            ];
            direction = { x: 1, y: 0 };
            nextDirection = { x: 1, y: 0 };
            score = 0;
            scoreValue.textContent = score;
            accumulator = 0;

            // 生成食物
            spawnFood();

            // 更新 UI
            menuScreen.classList.add('hidden');
            gameOverScreen.classList.add('hidden');
            pauseIndicator.classList.remove('visible');

            gameState = 'playing';
        }

        // 生成食物
        function spawnFood() {
            let newFood;
            do {
                newFood = {
                    x: Math.floor(Math.random() * GRID_COLS),
                    y: Math.floor(Math.random() * GRID_ROWS)
                };
            } while (snake.some(segment => segment.x === newFood.x && segment.y === newFood.y));
            food = newFood;
        }

        // 游戏结束
        function gameOver() {
            gameState = 'gameover';

            // 更新最高分
            if (score > highScore) {
                highScore = score;
                localStorage.setItem('snakeHighScore', highScore);
                highScoreValue.textContent = highScore;
                newHighScoreText.classList.remove('hidden');
            } else {
                newHighScoreText.classList.add('hidden');
            }

            finalScore.textContent = score;
            gameOverScreen.classList.remove('hidden');
        }

        // 切换暂停
        function togglePause() {
            if (gameState === 'playing') {
                gameState = 'paused';
                pauseIndicator.classList.add('visible');
            } else if (gameState === 'paused') {
                gameState = 'playing';
                pauseIndicator.classList.remove('visible');
                lastUpdateTime = performance.now();
            }
        }

        // 显示菜单
        function showMenu() {
            gameState = 'menu';
            menuScreen.classList.remove('hidden');
            gameOverScreen.classList.add('hidden');
            pauseIndicator.classList.remove('visible');
        }

        // 初始化游戏
        init();
    </script>
</body>
