                accumulator += deltaTime;
                while (accumulator >= moveInterval) {
                    update(moveInterval);
                    accumulator -= moveInterval;
                }
            }

            render();
            requestAnimationFrame(gameLoop);
        }

        // 游戏更新
        function update(deltaTime) {
            // 更新方向
            direction = { ...nextDirection };

            // 移动蛇
            const head = { ...snake[0] };
            head.x += direction.x;
            head.y += direction.y;

            // 穿墙逻辑
            if (head.x < 0) head.x = GRID_COLS - 1;
            if (head.x >= GRID_COLS) head.x = 0;
            if (head.y < 0) head.y = GRID_ROWS - 1;
            if (head.y >= GRID_ROWS) head.y = 0;

            // 检查是否撞到自己
            for (let i = 0; i < snake.length; i++) {
                if (head.x === snake[i].x && head.y === snake[i].y) {
                    gameOver();
                    return;
                }
            }

            // 添加新头部
            snake.unshift(head);

            // 检查是否吃到食物
            if (head.x === food.x && head.y === food.y) {
                score++;
                scoreValue.textContent = score;
                spawnFood();
            } else {
                // 如果没有吃到食物，移除尾部
                snake.pop();
            }
        }

        // 渲染游戏
        function render() {
            // 清除画布
            ctx.clearRect(0, 0, GAME_WIDTH, GAME_HEIGHT);

            // 绘制背景
            const gradient = ctx.createLinearGradient(0, 0, 0, GAME_HEIGHT);
            gradient.addColorStop(0, '#1a1a2e');
            gradient.addColorStop(1, '#16213e');
            ctx.fillStyle = gradient;
            ctx.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT);

            // 绘制网格线（可选，增加视觉效果）
            ctx.strokeStyle = 'rgba(255, 255, 255, 0.05)';
            ctx.lineWidth = 1;
            for (let x = 0; x <= GAME_WIDTH; x += CELL_SIZE) {
                ctx.beginPath();
                ctx.moveTo(x, 0);
                ctx.lineTo(x, GAME_HEIGHT);
                ctx.stroke();
            }
            for (let y = 0; y <= GAME_HEIGHT; y += CELL_SIZE) {
                ctx.beginPath();
                ctx.moveTo(0, y);
                ctx.lineTo(GAME_WIDTH, y);
                ctx.stroke();
            }

            // 绘制食物
            if (gameState === 'playing' || gameState === 'paused') {
                ctx.fillStyle = '#ff6b6b';
                ctx.shadowColor = '#ff6b6b';
                ctx.shadowBlur = 10;
                ctx.beginPath();
                ctx.arc(
                    food.x * CELL_SIZE + CELL_SIZE / 2,
                    food.y * CELL_SIZE + CELL_SIZE / 2,
                    CELL_SIZE / 2 - 2,
                    0,
                    Math.PI * 2
                );
                ctx.fill();
                ctx.shadowBlur = 0;
            }

            // 绘制蛇
            if (gameState === 'playing' || gameState === 'paused') {
                snake.forEach((segment, index) => {
                    const x = segment.x * CELL_SIZE;
                    const y = segment.y * CELL_SIZE;

                    // 蛇身渐变
                    const hue = (index * 5) % 360;
                    ctx.fillStyle = index === 0 ? '#4fd1c5' : `hsl(${hue}, 70%, 60%)`;
                    ctx.shadowColor = index === 0 ? '#4fd1c5' : `hsl(${hue}, 70%, 60%)`;
                    ctx.shadowBlur = index === 0 ? 8 : 4;

                    // 绘制圆角矩形
                    const radius = 4;
                    ctx.beginPath();
                    ctx.roundRect(x + 1, y + 1, CELL_SIZE - 2, CELL_SIZE - 2, radius);
                    ctx.fill();
                    ctx.shadowBlur = 0;

                    // 蛇头眼睛
                    if (index === 0) {
                        ctx.fillStyle = 'white';
                        const eyeSize = 3;
                        const eyeOffset = 5;
                        if (direction.x === 1) {
                            ctx.beginPath();
                            ctx.arc(x + CELL_SIZE - eyeOffset, y + eyeOffset, eyeSize, 0, Math.PI * 2);
                            ctx.arc(x + CELL_SIZE - eyeOffset, y + CELL_SIZE - eyeOffset, eyeSize, 0, Math.PI * 2);
                            ctx.fill();
                        } else if (direction.x === -1) {
                            ctx.beginPath();
                            ctx.arc(x + eyeOffset, y + eyeOffset, eyeSize, 0, Math.PI * 2);
                            ctx.arc(x + eyeOffset, y + CELL_SIZE - eyeOffset, eyeSize, 0, Math.PI * 2);
                            ctx.fill();
                        } else if (direction.y === -1) {
                            ctx.beginPath();
                            ctx.arc(x + eyeOffset, y + eyeOffset, eyeSize, 0, Math.PI * 2);
                            ctx.arc(x + CELL_SIZE - eyeOffset, y + eyeOffset, eyeSize, 0, Math.PI * 2);
                            ctx.fill();
                        } else if (direction.y === 1) {
                            ctx.beginPath();
                            ctx.arc(x + eyeOffset, y + CELL_SIZE - eyeOffset, eyeSize, 0, Math.PI * 2);
                            ctx.arc(x + CELL_SIZE - eyeOffset, y + CELL_SIZE - eyeOffset, eyeSize, 0, Math.PI * 2);
                            ctx.fill();
                        }
                    }
                });
            }
        }

        // 开始游戏
        function startGame() {
            // 重置游戏状态
            snake = [
                { x: Math.floor(GRID_COLS / 2), y: Math.floor(GRID_ROWS / 2) }
            ];
            direction = { x: 1, y: 0 };
            nextDirection = { x: 1, y: 0 };
            score = 0;
            scoreValue.textContent = score;
            accumulator = 0;

            // 生成食物
            spawnFood();

            // 更新 UI
            menuScreen.classList.add('hidden');
            gameOverScreen.classList.add('hidden');
            pauseIndicator.classList.remove('visible');

            gameState = 'playing';
        }

        // 生成食物
        function spawnFood() {
            let newFood;
            do {
                newFood = {
                    x: Math.floor(Math.random() * GRID_COLS),
                    y: Math.floor(Math.random() * GRID_ROWS)
                };
            } while (snake.some(segment => segment.x === newFood.x && segment.y === newFood.y));
            food = newFood;
        }

        // 游戏结束
        function gameOver() {
            gameState = 'gameover';

            // 更新最高分
            if (score > highScore) {
                highScore = score;
                localStorage.setItem('snakeHighScore', highScore);
                highScoreValue.textContent = highScore;
                newHighScoreText.classList.remove('hidden');
            } else {
                newHighScoreText.classList.add('hidden');
            }

            finalScore.textContent = score;
            gameOverScreen.classList.remove('hidden');
        }

        // 切换暂停
        function togglePause() {
            if (gameState === 'playing') {
                gameState = 'paused';
                pauseIndicator.classList.add('visible');
            } else if (gameState === 'paused') {
                gameState = 'playing';
                pauseIndicator.classList.remove('visible');
                lastUpdateTime = performance.now();
            }
        }

        // 显示菜单
        function showMenu() {
            gameState = 'menu';
            menuScreen.classList.remove('hidden');
            gameOverScreen.classList.add('hidden');
            pauseIndicator.classList.remove('visible');
        }

        // 初始化游戏
        init();
    </script>
